#ifndef NUMBER_THREADS
#define NUMBER_THREADS 256
#endif

#ifdef RD_WG_SIZE_0_0
#define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
#define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
#define BLOCK_SIZE RD_WG_SIZE
#else
#define BLOCK_SIZE 16
#endif

typedef float fp;

__kernel void extract_kernel(long d_Ne,
                             __global fp *d_I)
{
    int bx = get_group_id(0);
    int tx = get_local_id(0);
    long ei = (long)(bx * NUMBER_THREADS + tx);

    if (ei < d_Ne) {
        d_I[ei] = exp(d_I[ei] / (fp)255.0f);
    }
}

__kernel void prepare_kernel(long d_Ne,
                             __global fp *d_I,
                             __global fp *d_sums,
                             __global fp *d_sums2)
{
    int bx = get_group_id(0);
    int tx = get_local_id(0);
    long ei = (long)(bx * NUMBER_THREADS + tx);

    if (ei < d_Ne) {
        d_sums[ei] = d_I[ei];
        d_sums2[ei] = d_I[ei] * d_I[ei];
    }
}

__kernel void reduce_kernel(long d_Ne,
                            long d_no,
                            int d_mul,
                            __global fp *d_sums,
                            __global fp *d_sums2,
                            int d_blocks)
{
    int bx = get_group_id(0);
    int tx = get_local_id(0);
    int ei = bx * NUMBER_THREADS + tx;
    int nf = NUMBER_THREADS - (d_blocks * NUMBER_THREADS - (int)d_no);
    int df = 0;
    int i;

    __local fp d_psum[NUMBER_THREADS];
    __local fp d_psum2[NUMBER_THREADS];

    if ((long)ei < d_no) {
        d_psum[tx] = d_sums[(long)ei * d_mul];
        d_psum2[tx] = d_sums2[(long)ei * d_mul];
    } else {
        d_psum[tx] = (fp)0.0f;
        d_psum2[tx] = (fp)0.0f;
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    if (nf == NUMBER_THREADS) {
        for (i = 2; i <= NUMBER_THREADS; i = 2 * i) {
            if (((tx + 1) % i) == 0) {
                d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
            }
            barrier(CLK_LOCAL_MEM_FENCE);
        }

        if (tx == (NUMBER_THREADS - 1)) {
            d_sums[(long)bx * d_mul * NUMBER_THREADS] = d_psum[tx];
            d_sums2[(long)bx * d_mul * NUMBER_THREADS] = d_psum2[tx];
        }
    } else {
        if (bx != (d_blocks - 1)) {
            for (i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                if (((tx + 1) % i) == 0) {
                    d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                    d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
                }
                barrier(CLK_LOCAL_MEM_FENCE);
            }

            if (tx == (NUMBER_THREADS - 1)) {
                d_sums[(long)bx * d_mul * NUMBER_THREADS] = d_psum[tx];
                d_sums2[(long)bx * d_mul * NUMBER_THREADS] = d_psum2[tx];
            }
        } else {
            for (i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                if (nf >= i) {
                    df = i;
                }
            }

            for (i = 2; i <= df; i = 2 * i) {
                if (((tx + 1) % i) == 0 && tx < df) {
                    d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                    d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
                }
                barrier(CLK_LOCAL_MEM_FENCE);
            }

            if (tx == (df - 1)) {
                for (i = (bx * NUMBER_THREADS) + df; i < (bx * NUMBER_THREADS) + nf; i++) {
                    d_psum[tx] = d_psum[tx] + d_sums[i];
                    d_psum2[tx] = d_psum2[tx] + d_sums2[i];
                }

                d_sums[(long)bx * d_mul * NUMBER_THREADS] = d_psum[tx];
                d_sums2[(long)bx * d_mul * NUMBER_THREADS] = d_psum2[tx];
            }
        }
    }
}

__kernel void srad_kernel(fp lambda,
                          int Nr,
                          int Nc,
                          long Ne,
                          __global int *d_iN,
                          __global int *d_iS,
                          __global int *d_jE,
                          __global int *d_jW,
                          __global fp *d_dN,
                          __global fp *d_dS,
                          __global fp *d_dW,
                          __global fp *d_dE,
                          fp q0sqr,
                          __global fp *d_c,
                          __global fp *d_I)
{
    int bx = get_group_id(0);
    int tx = get_local_id(0);
    long ei = (long)(bx * NUMBER_THREADS + tx);

    if (ei < Ne) {
        int row = (int)(ei % (long)Nr);
        int col = (int)(ei / (long)Nr);

        fp Jc = d_I[ei];

        fp dN = d_I[d_iN[row] + Nr * col] - Jc;
        fp dS = d_I[d_iS[row] + Nr * col] - Jc;
        fp dW = d_I[row + Nr * d_jW[col]] - Jc;
        fp dE = d_I[row + Nr * d_jE[col]] - Jc;

        d_dN[ei] = dN;
        d_dS[ei] = dS;
        d_dW[ei] = dW;
        d_dE[ei] = dE;

        fp G2 = (dN * dN + dS * dS + dW * dW + dE * dE) / (Jc * Jc);
        fp L = (dN + dS + dW + dE) / Jc;

        fp num = (fp)0.5f * G2 - (fp)0.0625f * L * L;
        fp den = (fp)1.0f + (fp)0.25f * L;
        fp qsqr = num / (den * den);

        den = (qsqr - q0sqr) / (q0sqr * ((fp)1.0f + q0sqr));
        fp c = (fp)1.0f / ((fp)1.0f + den);

        if (c < (fp)0.0f) {
            c = (fp)0.0f;
        } else if (c > (fp)1.0f) {
            c = (fp)1.0f;
        }

        d_c[ei] = c;
    }
}

__kernel void srad2_kernel(fp lambda,
                           int Nr,
                           int Nc,
                           long Ne,
                           __global int *d_iN,
                           __global int *d_iS,
                           __global int *d_jE,
                           __global int *d_jW,
                           __global fp *d_dN,
                           __global fp *d_dS,
                           __global fp *d_dW,
                           __global fp *d_dE,
                           __global fp *d_c,
                           __global fp *d_I)
{
    int bx = get_group_id(0);
    int tx = get_local_id(0);
    long ei = (long)(bx * NUMBER_THREADS + tx);

    if (ei < Ne) {
        int row = (int)(ei % (long)Nr);
        int col = (int)(ei / (long)Nr);

        fp cN = d_c[ei];
        fp cS = d_c[d_iS[row] + Nr * col];
        fp cW = d_c[ei];
        fp cE = d_c[row + Nr * d_jE[col]];

        fp D = cN * d_dN[ei] + cS * d_dS[ei] + cW * d_dW[ei] + cE * d_dE[ei];

        d_I[ei] = d_I[ei] + (fp)0.25f * lambda * D;
    }
}

__kernel void compress_kernel(long d_Ne,
                              __global fp *d_I)
{
    int bx = get_group_id(0);
    int tx = get_local_id(0);
    long ei = (long)(bx * NUMBER_THREADS + tx);

    if (ei < d_Ne) {
        d_I[ei] = log(d_I[ei]) * (fp)255.0f;
    }
}
